1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ---- Edge case: empty policy ----
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // ---- Base premiums for single main items (+ fee) ----
15	  it.todo("single sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("single amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single potion → premium 45 G (40 base + 5 fee)");
19	
20	  // ---- Components and building blocks ----
21	  it.todo("2 runes → 50 G base premium (→ 55 G with fee)");
22	  it.todo("3 runes → 60 G base premium, block applies (→ 65 G with fee)");
23	  it.todo("4 runes → 100 G base premium, no block (→ 105 G with fee)");
24	  it.todo("7 runes → 175 G base premium (→ 180 G with fee)");
25	
26	  // ---- "Alike" components ----
27	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
29	
30	  // ---- Item-specific modifiers in isolation ----
31	  it.todo("cursed sword (steel, ench 3), newcomer → premium 165 G");
32	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (+30%)");
33	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
34	
35	  // ---- Modifier scope on multi-item policies ----
36	  it.todo("cursed sword + plain amulet → base 160 G, curse adds 50 G (of sword base) → 210 G before fee");
37	
38	  // ---- Policy-wide modifiers ----
39	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
40	  it.todo("first insurance → 10% initial assessment surcharge");
41	  it.todo("follow-up contract (2nd quote) → 15% discount on the contract");
42	
43	  // ---- Rounding ----
44	  it.todo("premium calc yielding 197.5 G → final premium 198 G (rounded up)");
45	  it.todo("payout calc yielding 350.5 G → final payout 350 G (rounded down)");
46	
47	  // ---- Claim: standard reimbursement ----
48	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full − 100 deductible)");
49	  it.todo("rune (value 250 G), damage 200 G → payout 100 G (full − 100 deductible)");
50	
51	  // ---- Claim: special clauses ----
52	  it.todo("dragon-material sword, ench 8, damage 1000 G → payout 400 G (50% then deductible)");
53	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (both clauses, 50% wins)");
54	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (dragon only: full then deductible)");
55	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (high-ench only: 50% then deductible)");
56	
57	  // ---- Claim: deductible per damage event ----
58	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");
59	
60	  // ---- Claim: multiple items of the same type ----
61	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
62	  it.todo("two sword damages, two swords insured → each is a separate damage with own deductible");
63	  it.todo("more damages of a type than insured (2 sword damages, 1 sword) → CLI exits non-zero, claim rejected");
64	
65	  // ---- Cap and insurance sum ----
66	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
67	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
68	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
69	  it.todo("sword (cap 2000), two claims of 1500 each → 1400 then 600; cap remaining 600 then 0");
70	
71	  // ---- Edge cases (errors) ----
72	  it.todo("quote with unknown item type (broomstick) → CLI exits non-zero, error to stderr, no results");
73	  it.todo("claim references item not in policy (amulet when only sword insured) → CLI exits non-zero, error to stderr");
74	  it.todo("claim with negative amount (-200) → CLI exits non-zero, error to stderr");
75	
76	  // ---- Integration examples ----
77	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
78	  it.todo("long-standing customer (3y) second contract, cursed sword (steel, ench 7) → premium 160 G");
79	});
